 87 static bool isSignTest(ICmpInst::Predicate &Pred, const APInt &C) {
 88   if (!ICmpInst::isSigned(Pred))
 89     return false;
 90 
 91   if (C.isZero())
 92     return ICmpInst::isRelational(Pred);
 93 
 94   if (C.isOne()) {
 95     if (Pred == ICmpInst::ICMP_SLT) {
 96       Pred = ICmpInst::ICMP_SLE;
